pub fn calculate_fee(byte_len: usize, fee_per_byte: u64) -> Option<u64> {
    let byte_len_u64: u64 = byte_len.try_into().ok()?;
    byte_len_u64.checked_mul(fee_per_byte)
}

pub fn calculate_storage_fee(bytes: usize, fee_per_byte: u64) -> Option<u64> {
    let bytes_u64: u64 = bytes.try_into().ok()?;
    bytes_u64.checked_mul(fee_per_byte)
}
